/**
 * Look up the hourly rate for a given county, worker type, and tier.
 * Returns null if any part of the key is not found.
 */
export function getRate(
  county: string,
  workerType: string,
  tier: string,
): number | null {
  const countyRates = (rates as RateTable)[county];
  if (!countyRates) return null;
  const tierPrices = countyRates[workerType];
  if (!tierPrices) return null;
  return tierPrices[tier] ?? null;
}

/**
 * Find which region a county belongs to.
 * Returns null if the county is not found in any region.
 */
export function getRegionForCounty(county: string): string | null {
  for (const [region, counties] of Object.entries(regionCounties)) {
    if ((counties as readonly string[]).includes(county)) {
      return region;
    }
  }
  return null;
}
